import{_ as s,C as a,o as l,c as n,j as i,a as t,E as d,ae as p}from"./chunks/framework.Bpn2sGEj.js";const f=JSON.parse('{"title":"Typing","description":"","frontmatter":{},"headers":[],"relativePath":"guide/typing.md","filePath":"guide/typing.md"}'),r={name:"guide/typing.md"},c={id:"typing",tabindex:"-1"};function u(h,e,m,g,y,b){const o=a("MarkdownLinkInline");return l(),n("div",null,[i("h1",c,[e[0]||(e[0]=t("Typing ",-1)),e[1]||(e[1]=i("a",{class:"header-anchor",href:"#typing","aria-label":'Permalink to "Typing"'},"​",-1)),e[2]||(e[2]=t()),d(o)]),e[3]||(e[3]=p(`<p>Slimgui has been developed with the following goals in mind:</p><ul><li>Support typing through <code>.pyi</code> files to enable good IDE support such as auto-complete, type checking, and docstrings.</li><li>Closely match the Dear ImGui API but adapt for Python as necessary. Don&#39;t invent new API concepts.</li></ul><p>The Slimgui API is similar to <a href="https://github.com/pyimgui/pyimgui" target="_blank" rel="noreferrer">pyimgui</a> except somewhat modernized:</p><ul><li>Enums in ImGui are exposed as typed Python enums using <code>enum.IntEnum</code> and <code>enum.IntFlag</code> to make it clear which API functions consume what type of enums.</li><li>Vector types such as <code>ImVec2</code>, <code>ImVec4</code>, and <code>float*</code> arrays are converted to Python tuples such as <code>tuple[float, float]</code> for <code>ImVec2</code> and <code>tuple[float, float, float, float]</code> for <code>ImVec4</code>.</li><li>Mutable bool args such as <code>bool* p_open</code> are input as normal <code>bool</code> values and returned as the second element of a 2-tuple. For example, <code>bool ImGui::Checkbox(const char* label, bool* v)</code> is translated to <code>def checkbox(label: str, v: bool) -&gt; tuple[bool, bool]</code>, where the first element is the boolean return value of <code>ImGui::Checkbox()</code> and the second element is the new checkbox state.</li></ul><h2 id="public-and-internal-types" tabindex="-1">Public and Internal Types <a class="header-anchor" href="#public-and-internal-types" aria-label="Permalink to &quot;Public and Internal Types&quot;">​</a></h2><p>Typical usage imports the public modules:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> slimgui </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> imgui</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> slimgui </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> implot</span></span></code></pre></div><p>The underlying bindings live under <code>slimgui.slimgui_ext.imgui</code> and <code>slimgui.slimgui_ext.implot</code>.</p><p>Those <code>slimgui_ext.*</code> modules exist because they expose the native binding layer directly. The public <code>slimgui.imgui</code> and <code>slimgui.implot</code> modules then build on top of that layer by:</p><ul><li>re-exporting many enums and binding types</li><li>adding some higher-level Python wrapper types</li></ul><p>For example, some API signatures use wrapper types such as:</p><ul><li><code>slimgui.imgui.WrappedContext</code></li><li><code>slimgui.implot.WrappedContext</code></li><li><code>slimgui.imgui.DrawList</code></li></ul><p>These are distinct from the lower-level types in <code>slimgui.slimgui_ext.*</code>, even when they are related internally.</p>`,13))])}const _=s(r,[["render",u]]);export{f as __pageData,_ as default};
